// --- INJECTED PHASE 5 FUNCTIONS ---
/**
 * Phase 5 Slice 1 Guest Memory Extraction
 * 
 * Deterministically extracts low-risk factual stay context from guest messages.
 * Guards high-risk truth by refusing to extract them casually.
 * 
 * Returns a canonical write payload ready for DB persistence (RPC or DML).
 */

function detectDisputeEscalationSubtype(text, currentMemory = {}) {
    const raw = String(text ?? '').trim();
    const normalized = raw.toLowerCase();

    // First check negative controls explicitly to avoid false positives
    const isNegativeControl = 
        /ปกติมัดจำคืนเมื่อไหร่/i.test(normalized) ||
        /ขอใบเสร็จ/i.test(normalized) ||
        /ปกติเช็กเอาต์/i.test(normalized) ||
        /ปกติเช็คเอาท์/i.test(normalized) ||
        /เซเว่นอยู่ตรงไหน/i.test(normalized);
    if (isNegativeControl) {
        return null;
    }

    // 1. Negative Review or Social Threat
    const hasReviewThreat = /(รีวิวแย่|รีวิว 1 ดาว|รีวิวประจาน|จะรีวิว|1 ดาว|ดิสเครดิต|ประจาน|social|post facebook|ลงเฟส|ลงกลุ่ม)/i.test(normalized);
    if (hasReviewThreat) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "negative_review_or_social_threat",
            emotional_signal: "threatening",
            authority_escalation: "review_threat",
            risk_flags: ["money", "threat"],
            recommended_mode: "internal_now"
        };
    }

    // 2. Fraud or Scam Accusation
    const hasFraudAccusation = /(โกง|หลอกลวง|ต้มตุ๋น|scam|fraud|cheat)/i.test(normalized);
    if (hasFraudAccusation) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "deposit_refund_dispute",
            emotional_signal: "angry",
            authority_escalation: "money_dispute",
            risk_flags: ["money", "accusation"],
            recommended_mode: "internal_now"
        };
    }

    // 3. Legal or Platform Escalation
    const hasLegalAuthority = /(ฟ้อง|ดำเนินคดี|ตำรวจ|แจ้งความ|legal|lawsuit)/i.test(normalized);
    const mentionsPlatform = /(booking\.com|agoda|airbnb|platform)/i.test(normalized);
    const hasPlatformEscalation = mentionsPlatform &&
        /(แจ้ง|ร้องเรียน|คอมเพลน|ฟ้อง|ดำเนินคดี|เอาเรื่อง|รีพอร์ต|report|complain|claim|ไม่จบ|ถ้าไม่|จะ)/i.test(normalized) &&
        !/(จองผ่าน|จองจาก|จองใน|จองทาง|booking channel|booked through)/i.test(normalized);
    if (hasLegalAuthority || hasPlatformEscalation) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "legal_or_platform_escalation",
            emotional_signal: "angry",
            authority_escalation: "legal_platform",
            risk_flags: ["legal", "platform"],
            recommended_mode: "internal_now"
        };
    }

    // 4. Owner or Manager Request
    const hasOwnerManager = /(คุยกับเจ้าของ|คุยกับผู้จัดการ|ติดต่อเจ้าของ|ติดต่อผู้จัดการ|ขอสายเจ้าของ|ขอสายผู้จัดการ|ขอคุยกับเจ้าของ|ขอคุยกับผู้จัดการ|talk to manager|talk to owner|contact manager|contact owner)/i.test(normalized);
    if (hasOwnerManager) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "owner_manager_request",
            emotional_signal: "frustrated",
            authority_escalation: "owner_manager",
            risk_flags: ["authority_required"],
            recommended_mode: "internal_now"
        };
    }

    // 5. Compensation Request
    const hasCompensation = /(ชดเชย|ค่าเสียเวลา|เยียวยา|ลดราคา|ส่วนลด|compensation|discount)/i.test(normalized);
    if (hasCompensation) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "compensation_request",
            emotional_signal: "frustrated",
            authority_escalation: "money_dispute",
            risk_flags: ["money", "compensation"],
            recommended_mode: "internal_now"
        };
    }

    // 6. Refund Request
    const hasRefund = /(คืนเงิน|ขอคืน|โอนคืน|refund)/i.test(normalized);
    if (hasRefund) {
        const isDepositDispute = /(มัดจำ|deposit)/i.test(normalized);
        const isCalm = /ครับ|ค่ะ|คะ|รบกวน|สอบถาม/i.test(normalized) && !/(เดี๋ยวนี้|ทันที|โกง|แย่|ช้า|ไม่พอใจ)/i.test(normalized);

        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: isDepositDispute ? "deposit_refund_dispute" : "refund_request",
            emotional_signal: isCalm ? "calm" : "angry",
            authority_escalation: "money_dispute",
            risk_flags: isCalm ? ["money"] : ["money", "refund"],
            recommended_mode: isCalm ? "draft_only" : "internal_now"
        };
    }

    // 7. Angry Complaint
    const hasAngryComplaint = /(แย่มาก|ห่วย|ช้ามาก|รอนาน|โมโห|หงุดหงิด|ไม่พอใจ|แย่|angry|disappointed|unacceptable)/i.test(normalized);
    if (hasAngryComplaint) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "angry_complaint",
            emotional_signal: "angry",
            authority_escalation: "out_of_sop",
            risk_flags: ["angry"],
            recommended_mode: "internal_now"
        };
    }

    // 8. General Deposit/Money Calm Questions (Account specific)
    const isCalmDepositQuery = /(เงินมัดจำ|มัดจำ).*?(เมื่อไหร่|กี่โมง|ตอนไหน|โอนคืน)/i.test(normalized) && 
        (/(ของผม|ของฉัน|ของเค้า|หนู|เรา|my)/i.test(normalized) || !/ปกติ/i.test(normalized));
    if (isCalmDepositQuery) {
        return {
            issue_family: "guest_dispute_escalation",
            issue_subtype: "deposit_refund_dispute",
            emotional_signal: "calm",
            authority_escalation: "money_dispute",
            risk_flags: ["money"],
            recommended_mode: "draft_only"
        };
    }

    return null;
}

function evaluateDisputeSendMode(dispute, guestText, currentMemory = {}) {
    if (!dispute) {
        return { send_mode: 'safe_auto', reason: 'non_dispute_factual_policy' };
    }

    const riskFlags = dispute.risk_flags || [];
    const subtype = dispute.issue_subtype;
    const emotional = dispute.emotional_signal;

    const isHighRisk = 
        emotional === 'angry' || 
        emotional === 'threatening' || 
        subtype === 'negative_review_or_social_threat' || 
        subtype === 'legal_or_platform_escalation' || 
        subtype === 'owner_manager_request' || 
        riskFlags.includes('threat') || 
        riskFlags.includes('accusation') ||
        riskFlags.includes('refund') ||
        riskFlags.includes('compensation') ||
        riskFlags.includes('legal');

    if (isHighRisk) {
        return { send_mode: 'internal_now', reason: `dispute_high_risk_${subtype}_${emotional}` };
    }

    if (subtype === 'deposit_refund_dispute' || subtype === 'refund_request' || riskFlags.includes('money')) {
        return { send_mode: 'draft_only', reason: `dispute_calm_account_specific_money` };
    }

    return { send_mode: 'internal_now', reason: `dispute_default_escalation` };
}

function detectCheckoutExtensionSubtype(text, currentMemory = {}) {
    const activeIssue = currentMemory['current_issue'];
    const isExtensionFollowUp = activeIssue?.value === 'checkout_extension_request' && !activeIssue.is_superseded;
    const hasCheckoutContext = /(เช็กเอาต์|เช็คเอาท์|เช็กเอาท์|เช็คเอาต์|checkout|check out|ออกจากห้อง|คืนห้อง)/i.test(text);
    const hasExplicitLateCue = /(ขอเลท|เลทเช็กเอาต์|เลทเช็คเอาท์|เลทเช็กเอาท์|เลทเช็คเอาต์|ขอออกเลท|ออกเลท|เลทได้ไหม|เลทได้มั้ย)/i.test(text);
    const hasLateTimeCue = /(บ่ายสอง|บ่ายโมง|เที่ยงครึ่ง|ออกบ่าย)/i.test(text);
    const isPolicyQuestion = /(เช็กเอาต์กี่โมง|เช็คเอาท์กี่โมง|เช็กเอาท์เวลา|เช็คเอาท์เวลา|เวลาเช็กเอาต์|เวลาเช็คเอาท์|ปกติเช็กเอาต์|ปกติเช็คเอาท์|ออกกี่โมง)/i.test(text) &&
        !/(เลท|ขอออก)/i.test(text);
    const isLateCheckout = hasExplicitLateCue || (hasCheckoutContext && hasLateTimeCue) || (isExtensionFollowUp && hasLateTimeCue);
    const isStayExtension = /(อยู่ต่อ|อีกคืน|พักต่อ|จองต่อ|เพิ่มอีก|คืนนี้ต่อ|ต่อห้อง)/i.test(text);
    const isPricingFollowUp = /(คิดเพิ่มเท่าไหร่|ขอฟรีได้ไหม|ไม่จ่ายเพิ่ม|ถ้าไม่ได้จะขอคืนเงิน|ฟรีได้ไหม|คิดเท่าไหร่|เท่าไหร่|กี่บาท)/i.test(text);

    if (isStayExtension) return 'stay_extension_request';
    if (isLateCheckout) return 'late_checkout_request';
    if (isPolicyQuestion) return 'checkout_policy_question';
    if (isExtensionFollowUp && isPricingFollowUp) {
        return currentMemory['current_issue_subtype']?.value || 'checkout_policy_question';
    }
    return null;
}

function extractMemory(message, currentMemory = {}, liveTruth = {}) {
    const text = message.text || '';
    const messageId = message.id || 'unknown';
    const timestamp = message.timestamp || new Date().toISOString();
    const actor = message.sender === 'system' ? 'system_extraction' : 'guest_extraction';

    const memory_actions = [];
    const ignored_actions = [];

    // Use a map to accumulate field updates before pushing
    const pendingUpdates = new Map();

    const recordUpdate = (field, value, confidence = 'high') => {
        const existing = currentMemory[field];

        if (field === 'local_needs_hints') {
            let currentArr = pendingUpdates.has(field) 
                ? pendingUpdates.get(field).new_value 
                : (existing?.value || []);

            if (!currentArr.includes(value)) {
                pendingUpdates.set(field, {
                    action: 'insert_and_supersede',
                    field,
                    new_value: [...currentArr, value],
                    confidence,
                    source_message_id: messageId,
                    actor,
                    timestamp,
                    supersedes_memory_id: existing?.id || null,
                    old_value: existing?.value || null
                });
            }
            return;
        }

        if (!existing || existing.value !== value) {
            pendingUpdates.set(field, {
                action: 'insert_and_supersede',
                field,
                new_value: value,
                confidence,
                source_message_id: messageId,
                actor,
                timestamp,
                supersedes_memory_id: existing?.id || null,
                old_value: existing?.value || null
            });
        }
    };

    // Helper to log ignored high-risk extraction attempts
    const recordIgnored = (field, reason) => {
        ignored_actions.push({
            field,
            source_message_id: messageId,
            reason
        });
    };

    const recordSupersedeOnly = (field, reason) => {
        const existing = currentMemory[field];
        if (!existing || existing.is_superseded) return;
        pendingUpdates.set(field, {
            action: 'mark_superseded',
            field,
            reason,
            confidence: existing.confidence || 'medium',
            source_message_id: messageId,
            actor,
            timestamp,
            supersedes_memory_id: existing.id || null,
            old_value: existing.value ?? null
        });
    };

    // 1. Travel Mode
    const mentionsTaxi = /(แท็กซี่|taxi|แกรป|grab|bolt)/i.test(text);
    const mentionsCar = /(ขับรถ|นั่งรถ|รถส่วนตัว|เอารถมา)/.test(text);
    const correctsAwayFromCar = /(บอกผิด|ไม่ได้เอารถ|ไม่เอารถ|เปลี่ยนใจ|เรียกแท็กซี่|นั่งแท็กซี่)/i.test(text);
    if (mentionsTaxi && (correctsAwayFromCar || !mentionsCar)) {
        recordUpdate('travel_mode', 'taxi');
    } else if (mentionsCar) {
        recordUpdate('travel_mode', 'car');
    }

    // 2. Parking Mode
    if (text.match(/(จอดรถ|ที่จอดรถ|ลานจอด)/)) {
        recordUpdate('parking_mode', 'needs_parking');
    }

    // 3. Current Location Hint
    if (text.match(/(ถึงหน้าตึก|ถึงคอนโด|อยู่หน้าตึก|ถึงแล้ว)/)) {
        recordUpdate('current_location_hint', 'at_building');
    } else if (text.match(/(กำลังเดินทาง|กำลังไป|บนรถ|ออกเดินทาง)/)) {
        recordUpdate('current_location_hint', 'on_the_way');
    } else if (text.match(/(ยังไม่ออกเดินทาง|ยังไม่ไป|ยังอยู่บ้าน|อยู่บ้าน)/)) {
        recordUpdate('current_location_hint', 'not_departed');
    } else if (text.match(/(คอสโม|cosmo|เดินห้าง|เดินเล่นในห้าง|เดินตลาด)/i)) {
        recordUpdate('current_location_hint', 'in_cosmo');
    } else if (text.match(/(อยู่ในห้อง|ขึ้นห้องแล้ว)/)) {
        recordUpdate('current_location_hint', 'in_room');
    } else if (text.match(/(อยู่ข้างนอก|ไม่แน่ใจ|ไม่รู้)/)) {
        recordUpdate('current_location_hint', 'unknown');
    }

    // 4. Arrival / Check-in / Check-out state
    if (text.match(/(รอเช็คอิน|เช็คอินได้ไหม|เข้าห้องได้หรือยัง)/)) {
        recordUpdate('arrival_state', 'waiting_to_check_in');
    } else if (text.match(/(เข้าห้องแล้ว|เช็คอินแล้ว|เปิดประตูแล้ว)/)) {
        recordUpdate('check_in_state', 'checked_in');
    } else if (text.match(/(เช็คเอาท์|ออกแล้ว|คืนห้อง|จะออกแล้ว)/)) {
        recordUpdate('check_out_state', 'checking_out');
    }

    // 5. Local Needs Hints
    if (text.match(/(หิว|ร้านอาหาร|ของกิน|กินข้าว)/)) {
        recordUpdate('local_needs_hints', 'food');
    }
    if (text.match(/(เซเว่น|seven|7-11)/i)) {
        recordUpdate('local_needs_hints', 'seven_eleven');
    }

    // 6. Purpose / Event Hint
    if (text.match(/(คอนเสิร์ต|concert|ดูคอน)/i)) {
        recordUpdate('purpose_context', 'concert');
    } else if (text.match(/(มาสอบ|เตรียมสอบ|ห้องสอบ)/)) {
        recordUpdate('purpose_context', 'exam');
    } else if (text.match(/(มาทำงาน|สัมมนา|ประชุม)/)) {
        recordUpdate('purpose_context', 'work');
    }

    // High-Risk Guard: Explicitly map high-risk terms to ignored bucket
    if (text.match(/(ชื่อผู้จอง|เจ้าของห้อง|เปลี่ยนชื่อ)/)) {
        recordIgnored('booking_identity', 'booking_identity is a high-risk field and requires stronger evidence or Internal Ops action.');
    }

    if (text.match(/(จ่ายเงิน|โอนเงิน|5000|สลิป)/)) {
        recordIgnored('payment_status', 'payment_status is a high-risk field and requires explicit Internal Ops or system verification.');
    }

    if (text.match(/(ขอรหัส|เปิดประตูให้หน่อย|รหัสห้อง)/)) {
        recordIgnored('room_access', 'room_access is safety-critical and must pass standard safety gates, not casual memory update.');
    }

    // 7. Service Recovery: Room Access Problem
    // Detect operational blockers for entering the room/building.
    // Explicitly exclude ordinary questions like "ขึ้นห้องยังไงครับ" that don't indicate a problem.
    const isOrdinaryQuestion = /(ยังไง|อย่างไร|วิธี|ขั้นตอน|กี่โมง|เมื่อไหร่)\b/i.test(text) && !/(เข้าไม่ได้|เปิดไม่ได้|ไปต่อไม่ได้|ไม่เจอ|หาไม่เจอ|หลง|ติด|stuck)/i.test(text);

    let accessProblemSubtype = null;

    if (!isOrdinaryQuestion) {
        if (/(เข้าไม่ได้|ไปต่อไม่ได้|เข้าตึกไม่ได้).*?(ตึก|อาคาร|หน้าตึก)/i.test(text) || /(stuck.*building|stuck.*ตึก)/i.test(text)) {
            accessProblemSubtype = 'stuck_at_building';
        } else if (/(หาทางเข้าไม่เจอ|หลง|ทางเข้า.*อยู่ไหน|ไปทางไหนต่อ)/i.test(text)) {
            accessProblemSubtype = 'cannot_find_building_path';
        } else if (/(ไม่เจอกุญแจ|กุญแจอยู่ไหน|หากุญแจไม่เจอ|หาคีย์การ์ดไม่เจอ|ไม่มีกุญแจ)/i.test(text) || (text.match(/หาไม่เจอ/i) && !text.match(/ทาง/))) {
            accessProblemSubtype = 'cannot_find_key';
        } else if (/(เปิดห้องไม่ได้|เปิดประตูไม่ได้|รหัสผิด|รหัสกดไม่ได้|เข้าห้องไม่ได้|เปิดไม่ออก)/i.test(text) || (text.match(/เปิดไม่ได้/i))) {
            accessProblemSubtype = 'cannot_open_room';
        } else if (/(ส่งวิธีขึ้นห้องอีกที|ขอวิธีเข้าห้องหน่อย|ส่งวิธี.*ให้หน่อย|ยังไม่ได้.*วิธี)/i.test(text) && /(ไปต่อไม่ได้|เข้าไม่ได้|หาไม่เจอ)/i.test(text)) {
            accessProblemSubtype = 'needs_access_resend';
        } else if (/(เข้าไม่ได้|ไปต่อไม่ได้)/i.test(text) && text.match(/หน้าตึก/i)) {
            accessProblemSubtype = 'stuck_at_building';
        }
    }

    if (accessProblemSubtype) {
        recordUpdate('current_issue', 'room_access_problem');
        recordUpdate('current_issue_subtype', accessProblemSubtype);
    }

    // Maintenance issues are operational problems and should replace any
    // older dispute/access issue as the active guest concern for follow-ups.
    let maintenanceSubtype = null;
    if (/(แอร์ไม่เย็น|แอร์เสีย|เครื่องปรับอากาศไม่เย็น)/i.test(text)) {
        maintenanceSubtype = 'aircon_not_cooling';
    } else if (/(น้ำหยด|น้ำรั่ว|ท่อน้ำรั่ว)/i.test(text)) {
        maintenanceSubtype = 'water_leak';
    } else if (/(ไฟดับ|ไฟไม่ติด|ปลั๊กเสีย)/i.test(text)) {
        maintenanceSubtype = 'electrical_issue';
    }
    if (maintenanceSubtype) {
        recordUpdate('current_issue', 'maintenance_problem');
        recordUpdate('current_issue_subtype', maintenanceSubtype);
    }

    // Phase 5 Slice 4: Delayed Check-in Detection
    const isCheckinIntent = /(เช็กอิน|เช็คอิน|พร้อมแล้ว|เข้าไปได้เลย|ขึ้นห้อง|ห้องพร้อม|จะเข้าห้อง|เข้าห้อง|หน้าตึก|หน้าอาคาร|ถึงตึก|ถึงอาคาร|อยู่ตึก)/i.test(text);
    const isAccessInstructionQuestion = /(ขึ้นห้อง|เข้าห้อง|เข้าอาคาร|เข้าตึก).*?(ยังไง|อย่างไร|วิธี|ขั้นตอน)/i.test(text);
    const isCheckinPolicyQuestion = /(เช็กอิน|เช็คอิน|check.?in).*?(กี่โมง|เวลา|เมื่อไหร่|ตอนไหน|when)/i.test(text);
    if (isCheckinIntent && !isAccessInstructionQuestion && !isCheckinPolicyQuestion && !accessProblemSubtype && !/(ขอเช็คอินก่อน|late checkout|early check|เช็คเอาท์|ออกแล้ว)/i.test(text)) {
        const blocker = resolveDelayedCheckinBlocker(liveTruth);
        if (blocker) {
            recordUpdate('current_issue', 'cleaning_delayed_checkin');
            recordUpdate('current_issue_subtype', blocker);
        }
    }

    // Phase 5 Slice 5: Checkout / Stay Extension
    const checkoutExtensionSubtype = detectCheckoutExtensionSubtype(text, currentMemory);

    if (checkoutExtensionSubtype) {
        recordUpdate('current_issue', 'checkout_extension_request');
        recordUpdate('current_issue_subtype', checkoutExtensionSubtype);
    }

    // Phase 5 Slice 6: Dispute Detection
    const dispute = detectDisputeEscalationSubtype(text, currentMemory);
    if (dispute) {
        const pendingIssue = pendingUpdates.get('current_issue')?.new_value;
        const pendingSubtype = pendingUpdates.get('current_issue_subtype')?.new_value;
        const preserveOperationalBlocker =
            pendingIssue === 'cleaning_delayed_checkin' &&
            dispute.issue_subtype === 'angry_complaint' &&
            pendingSubtype &&
            !/(คืนเงิน|ขอคืน|ชดเชย|รีวิว|ฟ้อง|booking\.com|agoda|airbnb|เจ้าของ|ผู้จัดการ|โกง)/i.test(text);
        if (!preserveOperationalBlocker) {
            recordUpdate('current_issue', 'guest_dispute_escalation');
            recordUpdate('current_issue_subtype', dispute.issue_subtype);
        }
        recordUpdate('emotional_signal', dispute.emotional_signal);
        recordUpdate('authority_escalation', dispute.authority_escalation);
    }

    const hasPendingIssue = pendingUpdates.has('current_issue');
    const activeIssue = currentMemory['current_issue'];
    const hasActiveOperationalIssue = activeIssue &&
        !activeIssue.is_superseded &&
        [
            'room_access_problem',
            'cleaning_delayed_checkin',
            'checkout_extension_request',
            'guest_dispute_escalation',
            'maintenance_problem'
        ].includes(activeIssue.value);
    const isShortIssueFollowUp = /^(ไม่ได้|ยังไม่ได้|อีกนาน|แล้วไง|เมื่อกี้|อันนั้น|ยัง|ทำไง|ช่วยดู|ไม่หาย|เหมือนเดิม)/i.test(text.trim());
    const isClearTopicShift =
        !isShortIssueFollowUp &&
        !hasPendingIssue &&
        (
            /(หิว|ร้านอาหาร|ของกิน|กินข้าว|เซเว่น|seven|7-11|ฟิตเนส|สระว่ายน้ำ|เพลง|ฝน|รถติด|เส้นทาง|แผนที่|ร้านขายยา|jett|cosmo)/i.test(text) ||
            /(บอกผิด|ไม่ได้เอารถ|ไม่เอารถ|เรียกแท็กซี่|นั่งแท็กซี่|แท็กซี่|taxi|grab|bolt)/i.test(text)
        ) &&
        !/(เข้าไม่ได้|เข้าตึกไม่ได้|เข้าห้องไม่ได้|เปิดไม่ได้|เปิดไม่ออก|ไม่เจอ|หาไม่เจอ|คืนเงิน|รีวิว|ฟ้อง|booking\.com|เจ้าของ|ผู้จัดการ|โกง|แอร์ไม่เย็น|แอร์เสีย|น้ำรั่ว|ไฟดับ)/i.test(text);

    if (hasActiveOperationalIssue && isClearTopicShift) {
        recordSupersedeOnly('current_issue', 'guest clearly shifted to a non-issue topic');
        recordSupersedeOnly('current_issue_subtype', 'guest clearly shifted to a non-issue topic');
    }

    pendingUpdates.forEach(update => {
        memory_actions.push(update);
    });

    return {
        memory_actions,
        ignored_actions
    };
}

/**
 * Phase 5 Slice 4: Resolve operational blocker for delayed check-in
 */
function resolveDelayedCheckinBlocker(liveTruth) {
    if (!liveTruth || !liveTruth.room_status) {
        return 'readiness_unknown';
    }
    const cleaningStatus = liveTruth.room_status.cleaning_status;
    if (!cleaningStatus || !['clean', 'dirty', 'in_progress'].includes(cleaningStatus)) {
        return 'readiness_unknown';
    }
    if (cleaningStatus !== 'clean') {
        if (liveTruth.cleaning_task?.dispatch_status === 'sent' && !liveTruth.cleaning_task?.acknowledged_at && liveTruth.cleaning_task?.priority === 'urgent') {
            return 'housekeeping_no_ack';
        }
        return 'cleaning_not_ready';
    }
    const accessPrepStatus = liveTruth.access_prep?.status;
    if (accessPrepStatus !== 'complete') {
        return 'access_prep_incomplete';
    }
    return null;
}

/**
 * Phase 5 Slice 1 Guest Memory Retrieval Core
 * 
 * Retrieves active-stay context based on guest intent, combining raw chat
 * evidence and structured memory without dumping all memory into the prompt.
 */

function buildRetrievalContext(intent, rawChatContext, structuredMemory, staySummary = null) {
    const MAX_RAW_CHAT_MESSAGES = 10;

    // 1. Always prioritize raw recent chat evidence if it's short
    const recentChat = rawChatContext.slice(-MAX_RAW_CHAT_MESSAGES);
    const contextLines = [];

    contextLines.push('--- RECENT CHAT EVIDENCE ---');
    recentChat.forEach(msg => {
        contextLines.push(`[${msg.sender.toUpperCase()}]: ${msg.text}`);
    });

    // 2. Select structured memory fields based on intent
    const relevantMemoryFields = [];

    const latestGuestText = [...recentChat].reverse().find((msg) => msg.sender === 'guest')?.text ?? '';
    const isShortIssueFollowUp = intent === 'general_chat' &&
        /^(ไม่ได้|ยังไม่ได้|อีกนาน|แล้วไง|เมื่อกี้|อันนั้น|ยัง|ทำไง|ช่วยดู|ไม่หาย|เหมือนเดิม)/i.test(String(latestGuestText).trim());
    const issueAwareIntent = intent === 'arrival_access' || intent === 'service_recovery' || isShortIssueFollowUp;

    // Elevate current_issue only when the current turn still needs issue context.
    if (issueAwareIntent && structuredMemory['current_issue'] && !structuredMemory['current_issue'].is_superseded) {
        if (!relevantMemoryFields.includes('current_issue')) relevantMemoryFields.push('current_issue');
        if (!relevantMemoryFields.includes('current_issue_subtype')) relevantMemoryFields.push('current_issue_subtype');
    }

    if (intent === 'arrival_access') {
        relevantMemoryFields.push('travel_mode', 'parking_mode', 'arrival_state', 'check_in_state', 'current_location_hint', 'room', 'room_access_readiness');
    } else if (intent === 'local_guidance') {
        relevantMemoryFields.push('current_location_hint', 'local_needs_hints', 'purpose_context', 'special_notes');
    } else if (intent === 'service_recovery') {
        relevantMemoryFields.push('room', 'check_in_state', 'emotional_signal');
    } else if (intent === 'general_chat') {
        // Just the basics
        relevantMemoryFields.push('current_location_hint');
    } else {
        // Fallback for unknown intent
        relevantMemoryFields.push('arrival_state', 'check_in_state');
    }

    // 3. Assemble structured memory block
    const memorySubset = {};
    for (const field of relevantMemoryFields) {
        if (structuredMemory[field] && !structuredMemory[field].is_superseded) {
            memorySubset[field] = structuredMemory[field].value;
        }
    }

    if (Object.keys(memorySubset).length > 0) {
        contextLines.push('');
        contextLines.push('--- RELEVANT STAY MEMORY ---');
        for (const [k, v] of Object.entries(memorySubset)) {
            // Flatten arrays for readable context
            const displayValue = Array.isArray(v) ? v.join(', ') : v;
            contextLines.push(`- ${k}: ${displayValue}`);
        }
    }

    // 4. Include Stay Summary if raw chat is truncated or intent demands deep context
    // Usually triggered if total chat > 50 messages, represented here by staySummary existence
    if (staySummary && (rawChatContext.length > MAX_RAW_CHAT_MESSAGES || intent === 'service_recovery')) {
        contextLines.push('');
        contextLines.push('--- STAY SUMMARY ---');
        contextLines.push(staySummary.summary_text);
    }

    return contextLines.join('\n');
}
/**
 * Phase 5 Slice 1 Stay Summary Generation Logic
 * 
 * Evaluates whether an active stay requires a new or refreshed summary
 * based on conversation length thresholds.
 */

const SUMMARY_THRESHOLD_INITIAL = 50;
const SUMMARY_THRESHOLD_REFRESH = 20;

function evaluateSummaryTrigger(rawChatContext, existingSummary = null) {
    const messageCount = rawChatContext.length;

    if (!existingSummary) {
        if (messageCount >= SUMMARY_THRESHOLD_INITIAL) {
            return {
                action: 'create_summary',
                message_count_at_generation: messageCount,
                instruction: 'Summarize the entire conversation history. Focus on guest needs, issues, and sentiment.'
            };
        }
    } else {
        const diff = messageCount - existingSummary.message_count_at_generation;
        if (diff >= SUMMARY_THRESHOLD_REFRESH) {
            return {
                action: 'refresh_summary',
                message_count_at_generation: messageCount,
                instruction: 'Update the existing summary with the latest context. Retain old critical issues.'
            };
        }
    }

    return {
        action: 'skip',
        reason: 'threshold_not_met'
    };
}

function normalizePolicyText(value) {
    return String(value ?? '').trim().toLowerCase();
}

function hasDelayedCheckinAuthorityEscalation(text) {
    return /(คืนเงิน|refund|ชดเชย|โกง|ฟ้อง|ผู้จัดการ|manager|เจ้าของ|รับผิดชอบ|ยกเลิกการจอง|cancel booking)/i.test(text);
}

function hasDelayedCheckinTimingPressure(text) {
    return /(อีกกี่นาที|อีกนานไหม|อีกนานมั้ย|เมื่อไหร่จะพร้อม|กี่โมงจะพร้อม|ตอนไหนจะพร้อม|พร้อมเมื่อไหร่|เสร็จหรือยัง|รอนานมาก|นานเกินไป)/i.test(text);
}

function evaluateDelayedCheckinPolicy({ guestText, blocker, currentMode = 'safe_auto' }) {
    const text = normalizePolicyText(guestText);

    if (currentMode === 'internal_now') {
        return { send_mode: 'internal_now', reason: 'existing_internal_now' };
    }

    if (hasDelayedCheckinAuthorityEscalation(text)) {
        return { send_mode: 'internal_now', reason: 'cleaning_delayed_checkin_authority_bound_escalation' };
    }

    if (blocker === 'readiness_unknown') {
        return { send_mode: 'draft_only', reason: 'cleaning_delayed_checkin_unknown_truth' };
    }

    if (currentMode === 'draft_only') {
        return { send_mode: 'draft_only', reason: 'existing_draft_only' };
    }

    if (hasDelayedCheckinTimingPressure(text)) {
        return { send_mode: 'draft_only', reason: 'cleaning_delayed_checkin_needs_timing_review' };
    }

    return { send_mode: 'safe_auto', reason: 'cleaning_delayed_checkin_safe_holding_reply' };
}

function buildDelayedCheckinHoldingReply(blocker) {
    switch (blocker) {
        case 'housekeeping_no_ack':
            return 'ตอนนี้ห้องยังไม่พร้อมเข้าพักนะคะ ทางทีมกำลังเร่งประสานงานให้ค่ะ รบกวนรอสักครู่นะคะ';
