}

/**
 * Phase 5 Slice 3: Deterministic Policy Gate
 * 
 * Enforces safe boundaries over LLM's recommended send mode.
 */
function evaluateSendMode(aiUnderstanding, intent) {
    const riskFlags = Array.isArray(aiUnderstanding.risk_flags) ? aiUnderstanding.risk_flags : [];
    const hasRisk = riskFlags.some(flag => flag !== 'none' && flag !== '');

    // 1 (Highest): Risk flags present
    if (hasRisk) {
        const hasHighRiskFlags = riskFlags.some(flag => ['threat', 'accusation', 'legal', 'platform', 'authority_required', 'angry', 'refund', 'compensation'].includes(flag));
        if (riskFlags.includes('money') && !hasHighRiskFlags) {
            return { send_mode: 'draft_only', reason: `calm_money_risk_draft_only` };
        }
        return { send_mode: 'internal_now', reason: `risk_flags_present: ${riskFlags.join(', ')}` };
    }

    // 2: Unknown SOP or intent
    if (aiUnderstanding.suggested_sop_family === 'unknown' || intent === 'unknown_knowledge_gap') {
        return { send_mode: 'internal_now', reason: 'unknown_sop_or_intent' };
    }

    // 3: Low confidence
    if (aiUnderstanding.confidence_level === 'low') {
        return { send_mode: 'internal_now', reason: 'low_confidence' };
    }

    // 4: Operational truth verification needed
    const truthRequiringIntents = ['early_checkin_request', 'extension_interest', 'late_checkout_request', 'room_move_request', 'service_recovery', 'compensation_request'];
    if (truthRequiringIntents.includes(intent) || aiUnderstanding.suggested_sop_family === 'service_recovery') {
        return { send_mode: 'draft_only', reason: `operational_truth_required` };
    }

    // 5: Medium confidence
    if (aiUnderstanding.confidence_level === 'medium') {
        return { send_mode: 'draft_only', reason: 'medium_confidence' };
    }

    // 6 (Lowest): Safe Auto
    return { send_mode: 'safe_auto', reason: 'low_risk_approved_sop' };
}

const MAINTENANCE = [
  [/แอร์.*(ไม่เย็น|เสีย|น้ำหยด|เสียงดัง)/, "aircon_not_cooling"],
  [/(น้ำรั่ว|น้ำหยด|ท่อแตก)/, "water_leak"],
  [/(ไฟดับ|ไฟไม่ติด)/, "electrical_problem"],
  [/(ควัน|กลิ่นไหม้|ไฟไหม้)/, "fire_or_smoke"],
];

function buildGuestIncidentCandidate({
  text,
  conversationId,
  bookingId,
  roomId,
  sourceEventId,
  correlationId,
  currentTopic,
  activeIncidents,
}) {
  const raw = String(text ?? '').trim();
  if (!raw) return null;

  let issueFamily = null;
  let issueSubtype = null;
  let severity = "normal";

  // 1. Check maintenance keywords
  for (const [pattern, subtype] of MAINTENANCE) {
    if (pattern.test(raw)) {
      issueFamily = "maintenance";
      issueSubtype = subtype;
      if (subtype === "fire_or_smoke") {
        severity = "urgent";
      }
      break;
    }
  }

  // 2. Check memory actions via extractMemory
  if (!issueFamily) {
    const memResult = extractMemory({ text: raw, id: sourceEventId || 'unknown' }, {}, {});
    const actions = memResult?.memory_actions || [];
    const issueAction = actions.find(a => a.field === 'current_issue');
    const subtypeAction = actions.find(a => a.field === 'current_issue_subtype');
    if (issueAction && subtypeAction) {
      issueFamily = issueAction.new_value;
      issueSubtype = subtypeAction.new_value;

      if (issueFamily === "checkout_extension_request" && issueSubtype === "checkout_policy_question") {
        return null;
      }

      if (issueFamily === "guest_dispute_escalation") {
        const emoAction = actions.find(a => a.field === 'emotional_signal');
        const emo = emoAction ? emoAction.new_value : 'calm';
        severity = (emo === 'angry' || emo === 'threatening' || ['negative_review_or_social_threat', 'legal_or_platform_escalation', 'owner_manager_request'].includes(issueSubtype)) ? 'urgent' : 'normal';
      } else if (issueFamily === "room_access_problem") {
        severity = "urgent";
      } else if (issueFamily === "cleaning_delayed_checkin") {
        severity = "urgent";
      } else if (issueFamily === "checkout_extension_request") {
        const isPricing = /(คิดเพิ่ม|จ่ายเพิ่ม|ฟรี|ไม่จ่ายเพิ่ม|คืนเงิน|เท่าไหร่|กี่บาท)/i.test(raw);
        severity = isPricing ? "urgent" : "high";
      }
    }
  }

  // 3. Check ambiguous follow up with active incident
  const isAmbiguous = /^(แล้วไง|อีกนานไหม|ยังไม่ได้|เมื่อกี้ล่ะ)$/i.test(raw);
  if (!issueFamily && isAmbiguous && Array.isArray(activeIncidents)) {
    const plausible = activeIncidents.filter(inc => inc.status !== "resolved" && inc.status !== "closed");
    if (plausible.length === 1) {
      issueFamily = plausible[0].issue_family;
      issueSubtype = plausible[0].issue_subtype;
      severity = plausible[0].severity || "normal";
    }
  }

  if (issueFamily && issueSubtype) {
    return {
      source_surface: "guest_oa",
      source_event_id: sourceEventId,
      correlation_id: correlationId,
      idempotency_key: `guest_oa:${sourceEventId}:${issueFamily}`,
      conversation_id: conversationId,
      booking_id: bookingId,
      room_id: roomId,
      issue_family: issueFamily,
      issue_subtype: issueSubtype,
      severity: severity,
      latest_evidence_text: text,
      requires_internal_ops: true,
      requires_owner: true
    };
  }

  return null;
}

function canAttachAmbiguousFollowUp(text, recentTurns, activeIncidents) {
  const ambiguous = /^(แล้วไง|อีกนานไหม|ยังไม่ได้|เมื่อกี้ล่ะ)$/i.test(text.trim());
  if (!ambiguous) return false;
  if (!Array.isArray(activeIncidents)) return false;
  const plausible = activeIncidents.filter((incident) => incident.status !== "resolved");
  if (plausible.length !== 1) return false;
  if (!Array.isArray(recentTurns) || recentTurns.length === 0) return false;
  return recentTurns[0]?.incident_id === plausible[0].id;
}

